def range_summary(nums):
    if not nums:  # empty list returns ''
        return ''

    distinct_nums = sorted(set(nums))
    result = []
    start_num = distinct_nums[0]

    for num in distinct_nums[1:]:
        if num == start_num + 1:
            continue
        elif num - start_num > 1:
            result.append(f"{start_num}-{start_num+1}")
            start_num = num
        else:
            result.append(str(start_num))
            start_num = num

    # handle the last number(s) in the list
    if start_num < distinct_nums[-1]:
        result.append(f"{start_num}-{distinct_nums[-1]}")
    else:
        result.append(str(start_num))

    return ','.join(result)
